import { ButtonBuilder, TextChannel, User, Message, InteractionCollector, ButtonInteraction, TimestampStylesString, Snowflake, ChatInputCommandInteraction, Client } from 'discord.js';
import util from 'util';

interface ProcessOptions {
    /**
     * @default 1900
     */
    limit?: number;
    /**
     * @default false
     */
    noCode?: boolean;
    secrets?: string[];
    lang?: string;
}
interface ActionOptions {
    manager: ProcessManager;
    [x: string]: any;
}
interface Action {
    button: ButtonBuilder;
    requirePage: boolean;
    action(options: ActionOptions): Promise<any> | any;
}
/**
 * Process Manager of every Process
 */
declare class ProcessManager {
    content: string;
    dokdo: Dokdo;
    options: ProcessOptions;
    target: TextChannel;
    messageContent: string;
    limit: number;
    splitted: string[];
    page: number;
    author: User;
    actions: Action[];
    wait: number;
    message?: Message;
    argument: never[];
    args: any;
    messageComponentCollector: InteractionCollector<ButtonInteraction> | undefined;
    private timer;
    private readonly rateLimitInterval;
    constructor(message: Context, content: string, dokdo: Dokdo, options?: ProcessOptions);
    init(): Promise<void>;
    addAction(actions: Action[], args?: Record<string, unknown>): Promise<void>;
    createMessageComponentMessage(): Promise<void>;
    filterSecret(string: string): string;
    updatePage(num: number): void;
    nextPage(): void;
    previousPage(): void;
    update(): void;
    edit(): Promise<void>;
    add(content: string): void;
    destroy(): void;
    genText(): string;
    splitContent(): string[];
}

declare class codeBlock {
    static construct(content: string, lang?: string): string;
    static parse(content: string): string[] | null;
}

declare class HLJS {
    static languages: string[];
    /**
     * Get highlight.js language of given query.
     */
    static getLang(query?: string | null): string | undefined;
}

declare class System {
    /**
     * Get memory info
     *
     * @returns {NodeJS.MemoryUsage}
     */
    static memory(): Partial<NodeJS.MemoryUsage>;
    static processReadyAt(): Date;
}

declare class DateFormatting {
    static _format(date: Date | number, style: TimestampStylesString): string;
    static relative(date: Date | number): string;
}

declare function count(argument: any): {
    name: string;
    count: number;
    ratio: string;
}[] | null;

declare function inspect(value: unknown, options: util.InspectOptions): string;

declare function table(obj: Record<string, any>): string;

declare function typeFind(argument: any): 'NaN' | 'Class' | 'Function' | string;

declare function isInstance(target: unknown, theClass: any): boolean;

declare const isGenerator: (target: Generator) => boolean;

declare function regexpEscape(string: string): string;

declare function join(arr: string[], sep: string, lastSep: string): string;

type Utils_Action = Action;
type Utils_ActionOptions = ActionOptions;
type Utils_DateFormatting = DateFormatting;
declare const Utils_DateFormatting: typeof DateFormatting;
type Utils_HLJS = HLJS;
declare const Utils_HLJS: typeof HLJS;
type Utils_ProcessManager = ProcessManager;
declare const Utils_ProcessManager: typeof ProcessManager;
type Utils_ProcessOptions = ProcessOptions;
type Utils_System = System;
declare const Utils_System: typeof System;
type Utils_codeBlock = codeBlock;
declare const Utils_codeBlock: typeof codeBlock;
declare const Utils_count: typeof count;
declare const Utils_inspect: typeof inspect;
declare const Utils_isGenerator: typeof isGenerator;
declare const Utils_isInstance: typeof isInstance;
declare const Utils_join: typeof join;
declare const Utils_regexpEscape: typeof regexpEscape;
declare const Utils_table: typeof table;
declare const Utils_typeFind: typeof typeFind;
declare namespace Utils {
  export {
    Utils_Action as Action,
    Utils_ActionOptions as ActionOptions,
    Utils_DateFormatting as DateFormatting,
    Utils_HLJS as HLJS,
    Utils_ProcessManager as ProcessManager,
    Utils_ProcessOptions as ProcessOptions,
    Utils_System as System,
    Utils_codeBlock as codeBlock,
    Utils_count as count,
    Utils_inspect as inspect,
    Utils_isGenerator as isGenerator,
    Utils_isInstance as isInstance,
    Utils_join as join,
    Utils_regexpEscape as regexpEscape,
    Utils_table as table,
    Utils_typeFind as typeFind,
  };
}

declare function main(message: Context, parent: Dokdo): Promise<void>;

declare function exec(message: Message, parent: Dokdo): Promise<void>;

declare function js(message: Context, parent: Dokdo): Promise<void>;

declare function shard(message: Message, parent: Dokdo): Promise<void>;

declare function jsi(message: Message, parent: Dokdo): Promise<void>;

declare function curl(message: Message, parent: Dokdo): Promise<void>;

declare function cat(message: Message, parent: Dokdo): Promise<void>;

declare const Commands_cat: typeof cat;
declare const Commands_curl: typeof curl;
declare const Commands_exec: typeof exec;
declare const Commands_js: typeof js;
declare const Commands_jsi: typeof jsi;
declare const Commands_main: typeof main;
declare const Commands_shard: typeof shard;
declare namespace Commands {
  export {
    Commands_cat as cat,
    Commands_curl as curl,
    Commands_exec as exec,
    Commands_js as js,
    Commands_jsi as jsi,
    Commands_main as main,
    Commands_shard as shard,
  };
}

interface DokdoOptions {
    aliases?: string[];
    owners?: Snowflake[];
    prefix?: string;
    secrets?: string[];
    globalVariable?: Record<string, any>;
    disableAttachmentExecution?: boolean;
    noPerm?(context: Message | ChatInputCommandInteraction): Promise<unknown>;
    isOwner?: (user: User) => boolean | Promise<boolean>;
}
interface MessageData {
    raw: string;
    command: string;
    type: string;
    args?: string;
}
declare module 'discord.js' {
    interface Message {
        data: MessageData;
    }
}
type Context = Message;
declare class Dokdo {
    client: Client;
    options: DokdoOptions;
    owners: Snowflake[];
    process: never[];
    /**
     * Main Client of Dokdo
     * @param client Discord Client
     * @param options Dokdo Options
     */
    constructor(client: Client, options: DokdoOptions);
    run(ctx: Context): Promise<void>;
    _addOwner(id: Snowflake): Snowflake[];
    _removeOwner(id: Snowflake): Snowflake[];
}

declare const _default: {
    Client: typeof Dokdo;
    Utils: typeof Utils;
    Commands: typeof Commands;
};

export { Dokdo as Client, Commands, Context, DokdoOptions, MessageData, Utils, _default as default };
